import escapeRegExp from 'lodash/escapeRegExp';
import { isString } from '../util';
import type { TreeSelectFilterTreeNodeFunc } from './interface';

export const defaultFilterTreeNode: TreeSelectFilterTreeNodeFunc = function (inputValue, { __node__: option }) {
  const { value, label, title } = option;
  // eslint-disable-next-line no-nested-ternary
  const keyword = isString(label) ? label : isString(title) ? title : value;
  return !inputValue || new RegExp(escapeRegExp(inputValue), 'gi').test(keyword);
};
